{
  "question": "PLG tier alongside consulting",
  "hypotheses": [
    {
      "id": "H1",
      "label": "Complementary growth engine",
      "description": "A self-serve PLG tier acts as a high-volume top-of-funnel that naturally upsells into higher-margin consulting engagements, creating a flywheel that accelerates both revenue streams.",
      "inconsistency_count": 0,
      "eliminated": false
    },
    {
      "id": "H2",
      "label": "Brand and margin dilution risk",
      "description": "Offering a low-cost PLG tier commoditizes the brand and cannibalizes consulting revenue, as clients opt for the cheaper self-serve option and perceive less need for premium advisory services.",
      "inconsistency_count": 7,
      "eliminated": true
    },
    {
      "id": "H3",
      "label": "Operational misalignment",
      "description": "The organizational capabilities, culture, and unit economics required to run a scalable PLG product are fundamentally different from those of a consulting practice, causing internal resource conflicts and strategic drift that undermine both motions.",
      "inconsistency_count": 0,
      "eliminated": false
    },
    {
      "id": "H4",
      "label": "PLG accelerates blended margins",
      "description": "A self-serve PLG tier generates high-margin, recurring revenue that subsidizes the lower-margin consulting engagements, improving overall blended gross margins and smoothing cash flow volatility.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H5",
      "label": "PLG cannibalizes consulting revenue",
      "description": "Offering a low-cost PLG tier causes existing and prospective consulting clients to down-tier into self-serve, eroding average contract value and net revenue per customer without sufficient volume gains to compensate.",
      "inconsistency_count": 6,
      "eliminated": false
    },
    {
      "id": "H6",
      "label": "PLG is a cash-flow drain with uncertain payback",
      "description": "The upfront engineering, infrastructure, and support investment required to build and maintain a PLG product creates a significant cash burn period with an extended and uncertain payback horizon that strains capital allocation away from the proven consulting business.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H7",
      "label": "Unified platform, segmented access",
      "description": "A single shared codebase and infrastructure can serve both self-serve PLG users and consulting-engaged clients through feature flags and entitlement layers, maximizing code reuse while minimizing tech debt divergence.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H8",
      "label": "Separate stacks create unsustainable debt",
      "description": "Maintaining a lightweight PLG product alongside a consulting-customized offering will inevitably fork the architecture, doubling engineering maintenance burden and degrading velocity on both fronts as the two diverge over time.",
      "inconsistency_count": 0,
      "eliminated": false
    },
    {
      "id": "H9",
      "label": "PLG as proving ground for productization",
      "description": "The PLG tier acts as a forcing function to harden, generalize, and standardize the consulting-born features into scalable, secure, multi-tenant product capabilities\u2014ultimately reducing per-client engineering effort and improving overall architecture quality.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H10",
      "label": "PLG accelerates consulting pipeline",
      "description": "A self-serve PLG tier acts as a powerful top-of-funnel acquisition channel, letting prospects experience the product's value firsthand so that a meaningful percentage naturally convert into high-value consulting engagements with shorter sales cycles.",
      "inconsistency_count": 0,
      "eliminated": false
    },
    {
      "id": "H11",
      "label": "PLG cannibalizes and dilutes premium brand",
      "description": "Offering a low-cost or free self-serve tier undermines the exclusivity and perceived expertise of the consulting brand, causing prospective enterprise buyers to anchor on lower price points and eroding the margins and positioning of the consulting practice.",
      "inconsistency_count": 7,
      "eliminated": true
    },
    {
      "id": "H12",
      "label": "Dual model succeeds only with strict segmentation",
      "description": "A PLG tier and consulting can coexist profitably, but only if the company enforces clear audience segmentation, distinct messaging tracks, and feature boundaries\u2014without which channel conflict and internal resource competition will stall growth in both motions.",
      "inconsistency_count": 0,
      "eliminated": false
    }
  ],
  "evidence": [
    {
      "id": "E1",
      "description": "Self-serve-to-consulting conversion rate and resulting ACV: the observed percentage of PLG users who upgrade into consulting engagements, and whether their average contract values match, exceed, or fall below those of prospects sourced through traditional sales channels\u2014directly discriminating between the flywheel thesis (H1/H10) and the cannibalization/price-anchoring thesis (H5/H11).",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E2",
      "description": "Consulting pipeline trajectory by source channel: whether the volume and value of consulting opportunities sourced from non-PLG channels (referrals, outbound, events) remains stable or declines after PLG launch, distinguishing true incremental top-of-funnel expansion (H1/H10) from substitution effects where prospects simply shift to the cheaper tier (H5).",
      "diagnostic_score": 0.25
    },
    {
      "id": "E3",
      "description": "Cumulative PLG investment versus time-to-positive-unit-economics: the total capital deployed on engineering, infrastructure, and support for the PLG tier and the quarter in which PLG contribution margin turns positive\u2014differentiating the blended-margin improvement thesis (H4) from the cash-drain-with-uncertain-payback thesis (H6).",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E4",
      "description": "Engineering velocity and code-divergence metrics across PLG and consulting-customized surfaces: measured feature-shipping cadence, percentage of shared versus forked code, and maintenance-ticket burden over time\u2014distinguishing the unified-platform thesis (H7/H9) from the unsustainable-tech-debt thesis (H8).",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E5",
      "description": "Enterprise buyer brand-perception and willingness-to-pay data segmented by PLG awareness: win/loss analyses and pricing-sensitivity surveys comparing enterprise prospects who have encountered the self-serve tier against those who have not, directly testing whether the PLG tier anchors price expectations and dilutes perceived expertise (H2/H11) or whether strict segmentation neutralizes that effect (H12).",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E6",
      "description": "Observed PLG-to-consulting conversion rate and resulting ACV of converted deals versus ACV of deals sourced through traditional direct sales \u2014 a high conversion rate with equal or higher ACV supports H1/H10 (flywheel/pipeline acceleration), while low conversion with lower ACV anchoring supports H5/H11 (cannibalization/brand dilution).",
      "diagnostic_score": 0.25
    },
    {
      "id": "E7",
      "description": "Fully-loaded unit economics of the PLG tier at current and projected scale (gross margin, CAC payback period, LTV/CAC) compared to the consulting practice \u2014 high PLG gross margins (>75%) with short payback differentiates H4 (blended margin improvement) from H6 (cash-flow drain with uncertain payback).",
      "diagnostic_score": 0.25
    },
    {
      "id": "E8",
      "description": "Revenue displacement tracking: change in consulting pipeline volume, win rate, and average contract value in segments where the PLG tier is available versus control segments where it is not \u2014 net additive pipeline supports H1/H10, while declining consulting ACV or win rates in PLG-exposed segments supports H2/H5.",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E9",
      "description": "Incremental engineering headcount and infrastructure spend required to maintain the PLG product as a percentage of total R&D budget, and whether the PLG and consulting offerings share a single deployable codebase or have diverged into separate branches \u2014 low incremental cost with shared codebase supports H7/H9, while rising dual-maintenance burden supports H3/H8.",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E10",
      "description": "Benchmarked outcomes from comparable B2B firms (e.g., Datadog, HubSpot, Palantir AIP) that operate PLG alongside professional services, specifically whether profitable coexistence required strict audience/feature segmentation or emerged organically \u2014 strict segmentation being a precondition supports H12, while organic upsell patterns support H1/H10.",
      "diagnostic_score": 0.25
    },
    {
      "id": "E11",
      "description": "Degree of codebase commonality across current consulting engagements: percentage of deliverables built on a shared core vs. bespoke per-client forks. High commonality supports H7 (unified platform feasible) and H9 (productization upside), while high fragmentation supports H8 (unsustainable divergence) and H6 (large upfront investment to converge).",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E12",
      "description": "Current architecture's multi-tenancy maturity \u2014 specifically whether tenant isolation, feature-flag infrastructure, entitlement/RBAC layers, and usage metering already exist or must be built from scratch. This directly differentiates H7 (segmented access on a single platform is achievable) from H8 (forking is inevitable) and sizes the capital outlay central to H6.",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E13",
      "description": "Engineering time allocation breakdown: proportion of sprints spent on client-specific customization versus generalizable, productizable feature work over the past 12 months. A heavy customization skew supports H3 (operational misalignment) and H6 (high retooling cost), while a product-oriented skew supports H9 (PLG as productization forcing function) and H4 (scalable margin improvement).",
      "diagnostic_score": 0.25
    },
    {
      "id": "E14",
      "description": "Observed self-serve-to-enterprise conversion rates and average upsell timelines from comparable B2B companies that added a PLG tier alongside services (e.g., GitLab, Databricks, HubSpot). High conversion rates with shorter sales cycles support H1/H10 (flywheel/pipeline acceleration); low conversion with high self-serve retention at lower tiers supports H5/H11 (cannibalization and brand dilution).",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E15",
      "description": "Historical client acquisition path data: how many current consulting clients first engaged through a free trial, freemium tool, or lightweight product experience versus pure outbound or referral. A strong product-led entry pattern supports H1/H10 (PLG as natural top-of-funnel); absence of this pattern supports H2/H12 (brand perception and strict segmentation requirements dominate).",
      "diagnostic_score": 0.25
    },
    {
      "id": "E16",
      "description": "Observed PLG-to-consulting conversion rate and upsell velocity: the percentage of self-serve users who upgrade to paid consulting engagements within 12 months, and the average time-to-conversion, benchmarked against industry PLG-to-enterprise conversion norms (typically 1-5%). A high conversion rate with short cycles supports H1/H10; a negligible rate with long or stalled cycles supports H5/H6.",
      "diagnostic_score": 0.25
    },
    {
      "id": "E17",
      "description": "Win/loss and brand perception data from enterprise prospects: whether buyers who encountered the PLG tier before engaging sales anchored on lower price points or perceived diminished consulting expertise versus those who entered through traditional channels. Price anchoring and lower willingness-to-pay supports H2/H11; higher trust and faster close rates supports H1/H10.",
      "diagnostic_score": 0.16666666666666666
    },
    {
      "id": "E18",
      "description": "Customer segment overlap analysis: the degree to which PLG sign-ups share firmographic profiles (company size, industry, budget authority) with existing or target consulting buyers. High overlap signals cannibalization risk (H5/H12); low overlap with a distinct SMB or developer persona supports complementary top-of-funnel positioning (H1/H10).",
      "diagnostic_score": 0.25
    },
    {
      "id": "E19",
      "description": "Competitive and analogous precedent data: revenue-mix trajectories and brand outcomes of comparable firms that launched PLG alongside services (e.g., HubSpot free-to-enterprise, Palantir Foundry self-serve, Gitlab open-core + professional services). Cases where consulting ACV held or grew post-PLG launch differentiate H1/H4 from H2/H5; cases where services revenue eroded support H5/H11.",
      "diagnostic_score": 0.25
    },
    {
      "id": "E20",
      "description": "Average contract value (ACV) and net revenue retention of consulting deals sourced via PLG versus traditional outbound/referral channels. If PLG-sourced consulting deals show comparable or higher ACV and expansion rates, it strongly supports H1/H10 and undermines H5/H11; materially lower ACVs or higher churn in PLG-sourced deals supports cannibalization and brand dilution hypotheses.",
      "diagnostic_score": 0.25
    }
  ],
  "surviving": [
    "H1",
    "H3",
    "H8",
    "H10",
    "H12",
    "H4",
    "H6",
    "H7",
    "H9",
    "H5"
  ],
  "eliminated": [
    "H2",
    "H11"
  ],
  "synthesis": {
    "conclusion": "The ACH exercise most strongly supports H1 (Complementary growth engine): a self-serve PLG tier acts as a high-volume top-of-funnel that naturally upsells into higher-margin consulting engagements, creating a flywheel that accelerates both revenue streams. H1 and the closely related H10 (PLG accelerates consulting pipeline) both survived with zero inconsistent evidence items out of twenty, while simultaneously accumulating the highest volume of consistent evidence (14 of 20 items each). The two cannibalization/brand-dilution hypotheses (H2 and H11) were decisively eliminated with 7 inconsistencies each, and H5 (cannibalization without volume offset) was effectively refuted with 6 inconsistencies, meaning the evidence base strongly disconfirms the fear that a PLG tier will erode consulting revenue or brand positioning. However, three risk-oriented hypotheses \u2014 H3 (operational misalignment), H8 (architectural debt from dual stacks), and H12 (success contingent on strict segmentation) \u2014 also survived with zero inconsistencies, albeit with far fewer pieces of consistent evidence (2, 5, and 5 respectively). This pattern suggests the flywheel thesis is well-supported, but that the path to realizing it carries real organizational and technical execution risks that the current evidence does not rule out. H1 is selected over H10 because it subsumes H10's pipeline-acceleration mechanism within a broader, more explanatory flywheel framing.",
    "winning_hypothesis_id": "H1",
    "confidence": "Medium",
    "confidence_reasoning": "Confidence is Medium rather than High for three reasons. First, while H1 has zero inconsistencies and dominant consistent evidence, the ACH methodology's core principle is disconfirmation, and three substantive risk hypotheses (H3, H8, H12) also carry zero inconsistencies \u2014 meaning the evidence collected so far is insufficiently diagnostic to rule out significant execution hazards. Second, the five most diagnostic evidence items (E2, E6, E7, E10, E13) all share a modest diagnosticity score of 0.25, indicating that no single piece of evidence sharply discriminates among the surviving hypotheses. Third, much of the evidence is coded as Neutral (N) against the risk hypotheses rather than Inconsistent (I), reflecting an absence of disconfirming data rather than positive refutation \u2014 a classic ACH caution flag. The conclusion would rise to High confidence if forthcoming operational and financial data (unit economics, engineering allocation, conversion rates) actively contradicted the risk hypotheses.",
    "key_uncertainties": [
      "Actual PLG-to-consulting conversion rate and resulting ACV of converted deals (E6): if conversion proves low or ACV anchors downward, H5 and H3 gain support at H1's expense.",
      "Fully-loaded PLG unit economics at scale (E7): if gross margins fall below ~75% or CAC payback extends beyond 18 months, the cash-drain hypothesis (H6) becomes more credible and undermines the blended-margin upside that reinforces the flywheel.",
      "Engineering time allocation between client-specific customization and generalizable product work (E13): a heavy customization skew would strengthen H3 (operational misalignment) and H8 (architectural divergence), challenging whether a single organization can run both motions effectively.",
      "Post-launch trajectory of non-PLG-sourced consulting pipeline (E2): a decline in referral/outbound/event-sourced pipeline after PLG launch would indicate substitution rather than true incremental growth, reviving the cannibalization thesis.",
      "Whether successful dual-model analogues (HubSpot, Datadog, Palantir AIP) required strict feature/audience segmentation or achieved organic upsell (E10): this benchmark evidence could tip the balance between H1 (organic flywheel) and H12 (success only with rigid segmentation)."
    ],
    "sensitivity_notes": "The conclusion is most sensitive to five evidence items, all sharing a diagnosticity score of 0.25 \u2014 the highest in this exercise. E2 (consulting pipeline trajectory by source) and E6 (PLG-to-consulting conversion rate and ACV) are the sharpest discriminators between the flywheel hypotheses (H1/H10) and the cannibalization hypothesis (H5); if either were re-evaluated from Consistent to Inconsistent for H1, the core thesis would be materially weakened. E7 (PLG unit economics) is the sole differentiator between H4 (blended margin improvement) and H6 (cash-flow drain); its current Consistent rating for H4 and Inconsistent for H6 is pivotal \u2014 reversing that coding would shift the financial narrative from upside to risk. E10 (benchmarked dual-model outcomes) is the primary lever for H12 (strict segmentation required); its current Consistent rating for both H12 and H10 leaves ambiguity about whether segmentation discipline is a prerequisite or merely helpful. E13 (engineering time allocation) is the key differentiator among the operational hypotheses (H3, H8, H9); it is currently Consistent with all three, meaning the data supports both the risk framing (misalignment, tech debt) and the opportunity framing (productization forcing function) simultaneously. Because no single evidence item exceeds 0.25 diagnosticity, the conclusion rests on the aggregate pattern rather than any decisive 'smoking gun.' A coordinated shift in just two or three of these five diagnostic items \u2014 for example, if conversion rates disappoint (E6), traditional pipeline shrinks (E2), and engineering skews toward customization (E13) \u2014 would be sufficient to shift the leading hypothesis from H1 to a risk-dominant framing (H3 or H12). Analysts should prioritize collecting hard operational data on these five dimensions before committing substantial capital to PLG buildout."
  },
  "timings": {
    "phase1_generate": 8.933075904846191,
    "phase2_evidence": 27.241228103637695,
    "phase3_matrix": 163.46289682388306,
    "phase4_eliminate": 0.002777099609375,
    "phase5_synthesis": 54.492351055145264
  }
}

{
  "question": "Competitor raised $20M, offering free audits",
  "hypotheses": [
    {
      "id": "H1",
      "label": "Land-and-expand market grab",
      "description": "The competitor is using free audits as a loss-leader to rapidly acquire customers and lock them into a broader paid platform, betting that switching costs will ensure long-term retention once the free period ends.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H2",
      "label": "Data harvesting for AI/product moat",
      "description": "The free audit strategy is primarily designed to ingest massive volumes of proprietary client data, which the competitor will use to train AI models or build benchmarking products that create an insurmountable competitive advantage.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H3",
      "label": "Unsustainable blitz to force acquisition",
      "description": "The competitor's strategy is a deliberately unsustainable cash-burn play aimed at disrupting market pricing and destroying incumbent margins long enough to either force a larger player to acquire them or to push weaker competitors out of the market.",
      "inconsistency_count": 5,
      "eliminated": false
    },
    {
      "id": "H4",
      "label": "Land-and-expand loss leader",
      "description": "The competitor is deliberately burning cash on free audits as a customer acquisition strategy, planning to upsell higher-margin advisory, remediation, or ongoing compliance services once embedded in the client relationship.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H5",
      "label": "Market share grab to force consolidation",
      "description": "The competitor is pursuing an aggressive below-cost pricing strategy funded by venture capital to rapidly capture market share, compress our margins, and either force us into a disadvantageous acquisition or push smaller players out of the market.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H6",
      "label": "Data/IP harvesting play",
      "description": "The free audits are primarily a mechanism to accumulate proprietary benchmark data, risk profiles, and industry intelligence at scale, which the competitor intends to monetize through a technology platform, AI product, or data-driven pricing advantage that fundamentally changes the unit economics of the audit business.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H7",
      "label": "Data harvesting play",
      "description": "The competitor is using free audits as a trojan horse to gain deep access to customers' technical environments and data, building a proprietary dataset that will power a defensible AI/analytics product or be used to undercut incumbents with highly targeted upsells.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H8",
      "label": "Unsustainable land-grab before pivot",
      "description": "The free audit offering is a venture-subsidized land-grab with no viable path to profitability at scale, and the competitor will either burn through the $20M within 12-18 months or be forced to pivot to a paid model once growth metrics plateau, giving us a window to fortify our platform and retain customers.",
      "inconsistency_count": 7,
      "eliminated": true
    },
    {
      "id": "H9",
      "label": "Automated audit engine moat",
      "description": "The competitor has built a highly automated, low-marginal-cost audit platform that makes free delivery economically sustainable, representing a genuine architectural leap that could permanently compress the market price for audits and threaten our revenue model.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H10",
      "label": "Data-driven valuation play",
      "description": "The competitor's primary goal is not near-term revenue but harvesting proprietary market and security-posture data at scale to train AI models or demonstrate network effects that justify a future fundraise or acquisition at a much higher valuation.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H11",
      "label": "Price-war commoditization strategy",
      "description": "The competitor is deliberately commoditizing the audit layer of the market to undermine the revenue base of incumbents like us, repositioning audits as a zero-cost expectation and shifting competitive differentiation\u2014and pricing power\u2014to an adjacent capability where they hold an advantage.",
      "inconsistency_count": 0,
      "eliminated": false
    }
  ],
  "evidence": [
    {
      "id": "E1",
      "description": "Competitor's hiring profile and team composition over the past 6 months \u2014 ratio of data scientists/ML engineers vs. sales/account executives vs. delivery consultants, indicating whether investment is oriented toward building a data/AI asset, an upsell motion, or brute-force audit delivery.",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E2",
      "description": "Scope and intrusiveness of data access requested during free audits \u2014 whether the competitor's engagement requires access significantly beyond what a standard audit demands (e.g., continuous API connections, broad telemetry ingestion, retention clauses in data agreements), which would differentiate data-harvesting hypotheses from pure customer-acquisition plays.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E3",
      "description": "Existence and maturity of adjacent paid offerings (remediation, managed compliance, advisory retainers) already being marketed or sold to free-audit customers, which would strongly differentiate land-and-expand/upsell hypotheses from data-harvesting or blitz-to-acquisition strategies.",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E4",
      "description": "Estimated marginal cost per audit delivered \u2014 evidence of heavy automation and tooling (low marginal cost suggesting a scalable platform moat) versus reliance on manual consultant labor (high marginal cost suggesting an unsustainable burn rate and time-limited threat window).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E5",
      "description": "Competitor's observable burn rate trajectory and signals of follow-on fundraising activity or M&A conversations \u2014 whether they are already in market for Series B or have engaged investment bankers, differentiating a short-runway blitz/acquisition-forcing play from a self-sustaining platform or long-horizon data strategy.",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E6",
      "description": "Competitor's estimated monthly burn rate and implied cash runway from the $20M raise (e.g., if delivering audits at ~$15K-$25K fully loaded cost each, how many can they fund and for how long) \u2014 a runway of <18 months supports unsustainable blitz hypotheses (H3/H5/H8), while a runway of 3+ years supports a low-marginal-cost automated engine (H9) or patient data accumulation play (H2/H6/H10).",
      "diagnostic_score": 0.09090909090909091
    },
    {
      "id": "E7",
      "description": "Whether the competitor has launched, announced, or is actively selling any paid adjacent products or services (advisory, remediation, continuous compliance, benchmarking dashboards) alongside the free audits \u2014 presence of a paid upsell motion supports land-and-expand (H1/H4), absence with no visible monetization path supports data harvesting (H2/H6/H7/H10) or forced-acquisition blitz (H3/H5).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E8",
      "description": "Competitor's headcount composition and hiring patterns \u2014 heavy investment in data science, ML engineers, and platform engineers relative to audit practitioners and sales staff supports automation/data moat hypotheses (H2/H6/H7/H9/H10), while heavy hiring of sales, advisory, and delivery staff supports land-and-expand upsell models (H1/H4).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E9",
      "description": "Scope and depth of data access and data-rights clauses the competitor requires in its free audit engagement terms \u2014 requests for access significantly beyond standard audit scope (e.g., broad API integrations, persistent agent deployment, expansive IP licensing in ToS) strongly supports data harvesting hypotheses (H2/H6/H7/H10), while standard-scope access points toward market-share or upsell plays (H1/H3/H4/H5).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E10",
      "description": "Degree of automation and human labor intensity observed in the competitor's audit delivery process (e.g., ratio of automated scanning/reporting to manual consultant hours per engagement) \u2014 a highly automated, low-touch delivery model supports H9 (architectural cost advantage) and H11 (permanent commoditization), while labor-intensive delivery confirms the offering is economically unsustainable and supports H3/H5/H8.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E11",
      "description": "Degree of automation in the competitor's audit delivery: observed ratio of engineering headcount to active audit engagements, use of agent-based scanning, and whether audits require significant manual analyst labor or run largely through an automated platform. A low marginal cost per audit supports H9; high manual labor intensity supports cash-burn hypotheses (H3, H5, H8).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E12",
      "description": "Scope of data access and contractual data rights: whether the competitor's audit engagement terms request persistent API access, broad telemetry collection, or data retention/usage rights far exceeding what a standard audit requires. Expansive data rights strongly differentiate data-harvesting hypotheses (H2, H6, H7, H10) from land-and-expand or commoditization plays (H1, H4, H11).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E13",
      "description": "Engineering hiring patterns and team composition: the ratio of ML/data-science hires vs. platform/infrastructure engineers vs. sales/solutions engineers in recent job postings and LinkedIn data. Heavy ML/data hiring supports H2/H6/H7/H10; heavy platform hiring supports H9; heavy sales/advisory hiring supports H1/H4/H11.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E14",
      "description": "Existence and maturity of adjacent paid product offerings: whether the competitor has shipped or is actively building paid remediation, continuous compliance monitoring, advisory, or benchmarking products alongside the free audit. A developed upsell stack supports H1/H4/H11; absence of adjacent products supports H3/H5/H8 (pure blitz) or H2/H6/H7/H10 (data play with delayed monetization).",
      "diagnostic_score": 0.18181818181818182
